import time
import math

def measure_runtime(func, n, repeats=3):
    times = []
    for _ in range(repeats):
        start = time.time()
        func(n)
        times.append(time.time() - start)
    return sum(times) / len(times)

def analyze_complexity(func, sizes):
    runtimes = []
    for n in sizes:
        t = measure_runtime(func, n)
        runtimes.append((n, t))
    return runtimes

def estimate_complexity(runtimes):
    """Estimate complexity by comparing growth rates."""
    if len(runtimes) < 2:
        return "Need more data points"

    # Calculate ratios as n doubles
    ratios = []
    for i in range(1, len(runtimes)):
        n1, t1 = runtimes[i-1]
        n2, t2 = runtimes[i]
        if t1 > 0:
            ratio = t2 / t1
            n_ratio = n2 / n1
            ratios.append((n_ratio, ratio))

    # Analyze ratios
    avg_ratio = sum(r[1] for r in ratios) / len(ratios)
    avg_n_ratio = sum(r[0] for r in ratios) / len(ratios)

    # Determine complexity
    if avg_ratio < 1.5:
        return "O(1) or O(log n)"
    elif avg_ratio < avg_n_ratio * 1.5:
        return f"O(n) - ratio ≈ {avg_ratio:.1f} when n×{avg_n_ratio:.0f}"
    elif avg_ratio < avg_n_ratio ** 1.7:
        return f"O(n log n) - ratio ≈ {avg_ratio:.1f}"
    elif avg_ratio < avg_n_ratio ** 2.5:
        return f"O(n²) - ratio ≈ {avg_ratio:.1f} when n×{avg_n_ratio:.0f}"
    else:
        return f"O(n³) or worse - ratio ≈ {avg_ratio:.1f}"

# Test algorithms
def linear_search(n):
    arr = list(range(n))
    target = n - 1
    for i in arr:
        if i == target:
            return i
    return -1

def bubble_sort(n):
    arr = list(range(n, 0, -1))
    for i in range(n):
        for j in range(n-i-1):
            if arr[j] > arr[j+1]:
                arr[j], arr[j+1] = arr[j+1], arr[j]
    return arr

def constant_time(n):
    return 42

def nlogn_sort(n):
    arr = list(range(n, 0, -1))
    return sorted(arr)

# Analyze
print("=== Complexity Analysis ===")

algorithms = [
    ("Constant", constant_time, [1000, 2000, 4000, 8000]),
    ("Linear search", linear_search, [10000, 20000, 40000, 80000]),
    ("Merge sort", nlogn_sort, [10000, 20000, 40000, 80000]),
    ("Bubble sort", bubble_sort, [500, 1000, 2000, 4000]),
]

for name, func, sizes in algorithms:
    print(f"\n{name}:")
    result = analyze_complexity(func, sizes)
    for n, t in result:
        print(f"  n={n}: {t:.6f}s")
    print(f"  Estimated: {estimate_complexity(result)}")

def verify_subset_sum(numbers: list, target: int, subset: list) -> bool:
    """Verify subset sum solution - O(k) where k is subset size."""
    # Check subset is valid
    for num in subset:
        if num not in numbers:
            return False
        # Check no duplicates (simple version)
        if subset.count(num) > numbers.count(num):
            return False

    # Check sum
    return sum(subset) == target

def verify_hamiltonian_path(graph: dict, path: list) -> bool:
    """Verify Hamiltonian path - O(V) verification."""
    nodes = set(graph.keys())

    # Check path visits all nodes
    if set(path) != nodes:
        return False

    # Check no repeated nodes
    if len(path) != len(nodes):
        return False

    # Check edges exist
    for i in range(len(path) - 1):
        if path[i+1] not in graph.get(path[i], []):
            return False

    return True

def verify_sat(formula: list, assignment: dict) -> bool:
    """Verify SAT solution - O(formula size)."""
    for clause in formula:
        clause_satisfied = False
        for literal in clause:
            var = abs(literal)
            value = assignment.get(var, False)
            if literal > 0 and value:
                clause_satisfied = True
                break
            if literal < 0 and not value:
                clause_satisfied = True
                break
        if not clause_satisfied:
            return False
    return True

def verify_graph_coloring(graph: dict, coloring: dict, k: int) -> bool:
    """Verify k-coloring - O(E) verification."""
    # Check all nodes colored with valid colors
    for node in graph:
        if node not in coloring:
            return False
        if coloring[node] < 1 or coloring[node] > k:
            return False

    # Check no adjacent nodes same color
    for node, neighbors in graph.items():
        for neighbor in neighbors:
            if coloring[node] == coloring.get(neighbor):
                return False

    return True

