import time

print("=== NP Verification Demo ===")

print("\n1. Subset Sum:")
numbers = [3, 7, 1, 8, 4, 2, 5, 9, 6]
target = 15

test_cases = [
    ([7, 8], True),      # 7+8=15 ✓
    ([3, 7, 5], True),   # 3+7+5=15 ✓
    ([1, 2, 3, 4, 5], True),  # 1+2+3+4+5=15 ✓
    ([3, 7], False),     # 3+7=10 ✗
    ([100], False),      # Not in numbers ✗
]

for subset, expected in test_cases:
    result = verify_subset_sum(numbers, target, subset)
    status = "✓" if result == expected else "✗"
    print(f"  {subset}: {result} {status}")

print("\n2. SAT:")
# (x1 OR x2) AND (NOT x1 OR x3) AND (NOT x2 OR NOT x3)
formula = [[1, 2], [-1, 3], [-2, -3]]

test_assignments = [
    ({1: True, 2: False, 3: True}, True),
    ({1: False, 2: True, 3: False}, True),
    ({1: True, 2: True, 3: True}, False),  # Last clause fails
]

for assignment, expected in test_assignments:
    result = verify_sat(formula, assignment)
    status = "✓" if result == expected else "✗"
    print(f"  {assignment}: {result} {status}")

print("\n3. Hamiltonian Path:")
graph = {
    'A': ['B', 'C'],
    'B': ['A', 'C', 'D'],
    'C': ['A', 'B', 'D'],
    'D': ['B', 'C']
}

test_paths = [
    (['A', 'B', 'C', 'D'], True),
    (['A', 'C', 'B', 'D'], True),
    (['A', 'B', 'D', 'C'], False),  # No edge B-D
    (['A', 'B', 'C'], False),       # Missing node
]

for path, expected in test_paths:
    result = verify_hamiltonian_path(graph, path)
    status = "✓" if result == expected else "✗"
    print(f"  {path}: {result} {status}")

print("\n4. Graph Coloring:")
coloring_tests = [
    ({'A': 1, 'B': 2, 'C': 1, 'D': 2}, 2, True),
    ({'A': 1, 'B': 1, 'C': 2, 'D': 2}, 2, False),  # A-B same
]

for coloring, k, expected in coloring_tests:
    result = verify_graph_coloring(graph, coloring, k)
    status = "✓" if result == expected else "✗"
    print(f"  {coloring}: {result} {status}")
